   379→        data: JSON.parse(m.data) as unknown,
   380→      })));
   381→    } catch (err) {
   382→      res.status(500).json({ error: String(err) });
   383→    }
   384→  });
   385→
   386→  // ─── V2 helpers ─────────────────────────────────────────────────────────────
   387→
   388→  type V2Session = {
   389→    summary: {
   390→      intent: string; outcome: string;
   391→      openItems: { id: number; text: string; status: string; subSessionId: string | null }[];
   392→      frictionItems: { text: string }[];
   393→      repoLearnings: { text: string }[];
   394→      codeLearnings: { path: string; finding: string }[];
   395→      workflowLearnings: { text: string }[];
   396→    } | null;
   397→  };
   398→
   399→  function mapV2Summary(summary: NonNullable<V2Session["summary"]>) {
   400→    return {
   401→      intent:            summary.intent,
   402→      outcome:           summary.outcome,
   403→      openItems:         summary.openItems.map((r) => ({ id: r.id, text: r.text, status: r.status, subSessionId: r.subSessionId })),
   404→      friction:          summary.frictionItems.map((r) => r.text),
   405→      repoLearnings:     summary.repoLearnings.map((r) => r.text),
   406→      codeLearnings:     summary.codeLearnings.map((r) => ({ path: r.path, finding: r.finding })),
   407→      workflowLearnings: summary.workflowLearnings.map((r) => r.text),
   408→    };
   409→  }
   410→
   411→  const V2_SESSION_INCLUDE = {
   412→    summary: {
   413→      include: {
   414→        openItems:         true,
   415→        frictionItems:     true,
   416→        repoLearnings:     true,
   417→        codeLearnings:     true,
   418→        workflowLearnings: true,
   419→      },
   420→    },
   421→  } as const;
   422→
   423→  const V2_SESSION_ORDER = { createdAt: "desc" as const };
   424→
   425→  // GET /api/v2/checkpoints
   426→  app.get("/api/v2/checkpoints", async (_req, res) => {
   427→    try {
   428→      const checkpoints = await db.checkpointMetadata.findMany({
   429→        include: {
   430→          tokenUsage: true,
   431→          filesTouched: { include: { filePath: true } },
   432→        },
   433→      });
   434→
   435→      const checkpointIds = checkpoints.map((c) => c.checkpointId);
   436→
   437→      const sessions = await db.checkpointSessionMetadata.findMany({
   438→        where:   { checkpointId: { in: checkpointIds } },
   439→        orderBy: V2_SESSION_ORDER,
   440→        include: V2_SESSION_INCLUDE,
   441→      });
   442→
   443→      // Group sessions by checkpointId
   444→      const sessionsByCheckpoint = new Map<string, typeof sessions>();
   445→      for (const s of sessions) {
   446→        const arr = sessionsByCheckpoint.get(s.checkpointId) ?? [];
   447→        arr.push(s);
   448→        sessionsByCheckpoint.set(s.checkpointId, arr);
   449→      }
   450→
   451→      res.json(checkpoints.map((c) => {
   452→        const cpSessions = sessionsByCheckpoint.get(c.checkpointId) ?? [];
   453→        const summary = cpSessions.find((s) => s.summary)?.summary ?? null;
   454→        const latestCreatedAt = cpSessions
   455→          .filter((s): s is typeof s & { createdAt: Date } => s.createdAt !== null)
   456→          .map((s) => s.createdAt)
   457→          .sort((a, b) => b.getTime() - a.getTime())[0] ?? null;
   458→        return {
   459→          id:               c.id,
   460→          checkpointId:     c.checkpointId,
   461→          cliVersion:       c.cliVersion,
   462→          strategy:         c.strategy,
   463→          branch:           c.branch,
   464→          checkpointsCount: c.checkpointsCount,
   465→          createdAt:        latestCreatedAt?.toISOString() ?? null,
   466→          tokenUsage: c.tokenUsage ? {
   467→            inputTokens:         c.tokenUsage.inputTokens,
   468→            cacheCreationTokens: c.tokenUsage.cacheCreationTokens,
   469→            cacheReadTokens:     c.tokenUsage.cacheReadTokens,
   470→            outputTokens:        c.tokenUsage.outputTokens,
   471→            apiCallCount:        c.tokenUsage.apiCallCount,
   472→          } : null,
   473→          filesTouched:  c.filesTouched.map((f) => f.filePath.path),
   474→          sessionCount:  cpSessions.length,
   475→          summary: summary ? mapV2Summary(summary) : null,
   476→        };
   477→      }));
   478→    } catch (err) {
   479→      res.status(500).json({ error: String(err) });
   480→    }
   481→  });
   482→
   483→  // GET /api/v2/checkpoints/:id
   484→  app.get("/api/v2/checkpoints/:id", async (req, res) => {
   485→    try {
   486→      const checkpointId = req.params.id;
   487→      const checkpoint = await db.checkpointMetadata.findUnique({
   488→        where: { checkpointId },
   489→        include: {
   490→          tokenUsage: true,
   491→          filesTouched: { include: { filePath: true } },
   492→        },
   493→      });
   494→      if (!checkpoint) { res.status(404).json({ error: "Not found" }); return; }
   495→
   496→      const sessions = await db.checkpointSessionMetadata.findMany({
   497→        where:   { checkpointId },
   498→        orderBy: V2_SESSION_ORDER,
   499→        include: V2_SESSION_INCLUDE,
   500→      });
   501→
   502→      const summary = sessions.find((s) => s.summary)?.summary ?? null;
   503→
   504→      res.json({
   505→        id:               checkpoint.id,
   506→        checkpointId:     checkpoint.checkpointId,
   507→        cliVersion:       checkpoint.cliVersion,
   508→        strategy:         checkpoint.strategy,
   509→        branch:           checkpoint.branch,
   510→        checkpointsCount: checkpoint.checkpointsCount,
   511→        tokenUsage: checkpoint.tokenUsage ? {
   512→          inputTokens:         checkpoint.tokenUsage.inputTokens,
   513→          cacheCreationTokens: checkpoint.tokenUsage.cacheCreationTokens,
   514→          cacheReadTokens:     checkpoint.tokenUsage.cacheReadTokens,
   515→          outputTokens:        checkpoint.tokenUsage.outputTokens,
   516→          apiCallCount:        checkpoint.tokenUsage.apiCallCount,
   517→        } : null,
   518→        filesTouched:  checkpoint.filesTouched.map((f) => f.filePath.path),
   519→        sessionCount:  sessions.length,
   520→        summary:       summary ? mapV2Summary(summary) : null,
   521→      });
   522→    } catch (err) {
   523→      res.status(500).json({ error: String(err) });
   524→    }
   525→  });
   526→
   527→  // GET /api/v2/sessions/:id/checkpoints
   528→  app.get("/api/v2/sessions/:id/checkpoints", async (req, res) => {
   529→    try {
   530→      const sessionId = req.params.id;
   531→      const sessionRows = await db.checkpointSessionMetadata.findMany({
   532→        where:   { sessionId },
   533→        orderBy: { createdAt: "asc" },
   534→        include: {
   535→          ...V2_SESSION_INCLUDE,
   536→          tokenUsage:   true,
   537→          filesTouched: { include: { filePath: true } },
   538→        },
   539→      });
   540→
   541→      res.json(sessionRows.map((s) => ({
   542→        checkpointId: s.checkpointId,
   543→        cliVersion:   s.cliVersion,
   544→        branch:       s.branch,
   545→        createdAt:    s.createdAt?.toISOString() ?? null,
   546→        tokenUsage:   s.tokenUsage ? {
   547→          inputTokens:         s.tokenUsage.inputTokens,
   548→          cacheCreationTokens: s.tokenUsage.cacheCreationTokens,
   549→          cacheReadTokens:     s.tokenUsage.cacheReadTokens,
   550→          outputTokens:        s.tokenUsage.outputTokens,
   551→          apiCallCount:        s.tokenUsage.apiCallCount,
   552→        } : null,
   553→        filesTouched: s.filesTouched.map((f) => f.filePath.path),
   554→        summary:      s.summary ? mapV2Summary(s.summary) : null,
   555→      })));
   556→    } catch (err) {
   557→      res.status(500).json({ error: String(err) });
   558→    }
   559→  });
   560→
   561→  // PATCH /api/open-items/:id
   562→  app.patch("/api/open-items/:id", async (req, res) => {
   563→    const id = parseInt(req.params.id, 10);
   564→    const { status, subSessionId } = req.body as { status?: string; subSessionId?: string };
   565→    const allowed = ["open", "in_progress", "complete", "na"];
   566→    if (status !== undefined && !allowed.includes(status)) {
   567→      res.status(400).json({ error: "status must be open, in_progress, or complete" });
   568→      return;
   569→    }
   570→    try {
   571→      const updated = await db.openItem.update({
   572→        where: { id },
   573→        data: {
   574→          ...(status !== undefined ? { status } : {}),
   575→          ...(subSessionId !== undefined ? { subSessionId } : {}),
   576→        },
   577→      });
   578→      res.json({ id: updated.id, status: updated.status, subSessionId: updated.subSessionId });
   579→    } catch (err) {
   580→      res.status(500).json({ error: String(err) });
   581→    }
   582→  });
   583→
   584→  // POST /api/sessions/spawn
   585→  app.post("/api/sessions/spawn", async (req, res) => {
   586→    const { prompt, cwd, openItemIds, parentSessionId } = req.body as { prompt?: string; cwd?: string; openItemIds?: number[]; parentSessionId?: string };
   587→    if (!prompt || typeof prompt !== "string") {
   588→      res.status(400).json({ error: "prompt is required" });
   589→      return;
   590→    }
   591→    try {
   592→      const safeCwd = (cwd ?? process.env.HOME ?? "/tmp").replace(/'/g, "'\\''");
   593→      const safePrompt = prompt.replace(/'/g, "'\\''").replace(/\\/g, "\\\\").replace(/"/g, '\\"');
   594→      // Pass open item IDs and parent session so the SessionStart hook can link back
   595→      const envParts: string[] = [];
   596→      if (openItemIds?.length) envParts.push(`GOSSAMER_SPAWN_OPEN_ITEMS='${openItemIds.join(",")}'`);
   597→      if (parentSessionId) envParts.push(`GOSSAMER_SPAWN_PARENT_SESSION='${parentSessionId.replace(/'/g, "")}'`);
   598→      const envPrefix = envParts.length ? envParts.join(" ") + " " : "";
   599→      // Use AppleScript to open a new Terminal window running claude interactively
   600→      const script = [
   601→        `tell application "Terminal"`,
   602→        `  activate`,
   603→        `  do script "cd '${safeCwd}' && ${envPrefix}claude '${safePrompt}'"`,
   604→        `end tell`,
   605→      ].join("\n");
   606→      execSync(`osascript -e '${script.replace(/'/g, "'\\''")}'`);
   607→      // Mark selected open items as in_progress
   608→      if (openItemIds?.length) {
   609→        await db.openItem.updateMany({
   610→          where: { id: { in: openItemIds } },
   611→          data: { status: "in_progress" },
   612→        });
   613→      }
   614→      res.json({ started: true });
   615→    } catch (err) {
   616→      res.status(500).json({ error: String(err) });
   617→    }
   618→  });
   619→
   620→  // Create HTTP server and attach WebSocket server (shared port)
   621→  const httpServer = createServer(app);
   622→  const wss = new WebSocketServer({ server: httpServer });
   623→
   624→  // WebSocket change detection — poll every 2s, broadcast on new events or checkpoints
   625→  let lastMaxEventId: number | null = null;
   626→  let lastMaxCheckpointId: number | null = null;
   627→  const broadcast = () => {
   628→    const message = JSON.stringify({ type: "sessions_updated" });
   629→    for (const client of wss.clients) {
   630→      if (client.readyState === WebSocket.OPEN) {
   631→        client.send(message);
   632→      }
   633→    }
   634→  };
   635→  const poller = setInterval(async () => {
   636→    try {
   637→      const [latestEvent, latestCheckpoint] = await Promise.all([
   638→        db.event.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   639→        db.checkpointMetadata.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   640→      ]);
   641→      const currentEventId = latestEvent?.id ?? null;
   642→      const currentCheckpointId = latestCheckpoint?.id ?? null;
   643→      if (currentEventId !== lastMaxEventId || currentCheckpointId !== lastMaxCheckpointId) {
   644→        lastMaxEventId = currentEventId;
   645→        lastMaxCheckpointId = currentCheckpointId;
   646→        broadcast();
   647→      }
   648→    } catch {
   649→      // Non-fatal polling error — keep running
   650→    }
   651→  }, 2000);
   652→
   653→  // ── Checkpoint auto-indexer ───────────────────────────────────────────────
   654→
   655→  const WORKTREE_PATH = "/tmp/gossamer-checkpoints";
   656→  const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
   657→  let checkpointPoller: ReturnType<typeof setInterval> | null = null;
   658→
   659→  if (repoDir) {
   660→    // Ensure worktree exists (reuse across restarts)
   661→    if (!existsSync(WORKTREE_PATH)) {
   662→      try {
   663→        // Prune stale worktree registration first, then re-add
   664→        execSync(`git -C ${JSON.stringify(repoDir)} worktree prune`, { stdio: "pipe" });
   665→        execSync(
   666→          `git -C ${JSON.stringify(repoDir)} worktree add ${JSON.stringify(WORKTREE_PATH)} ${CHECKPOINT_BRANCH}`,
   667→          { stdio: "pipe" },
   668→        );
   669→        process.stderr.write(`checkpoint indexer: worktree created at ${WORKTREE_PATH}\n`);
   670→      } catch (err) {
   671→        process.stderr.write(`checkpoint indexer: failed to create worktree — ${err}\n`);
   672→      }
   673→    }
   674→
   675→    const runIndex = async () => {
   676→      if (!existsSync(WORKTREE_PATH)) return;
   677→      try {
   678→        // Pull latest commits into the worktree working tree
   679→        execSync(`git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard HEAD`, { stdio: "pipe" });
   680→      } catch { /* non-fatal */ }
   681→      try {
   682→        const { checkpoints } = await indexAllCheckpointsV2(db, WORKTREE_PATH, undefined, repoDir);
   683→        if (checkpoints > 0) {
   684→          process.stderr.write(`checkpoint indexer: indexed ${checkpoints} checkpoints\n`);
   685→          broadcast();
   686→        }
   687→      } catch { /* non-fatal */ }
   688→    };
   689→
   690→    void runIndex();
   691→    checkpointPoller = setInterval(runIndex, 30_000);
   692→    process.stderr.write(`checkpoint indexer: polling every 30s (worktree: ${WORKTREE_PATH})\n`);
   693→  }
   694→
   695→  // Graceful shutdown
   696→  const shutdown = () => {
   697→    clearInterval(poller);
   698→    if (checkpointPoller) clearInterval(checkpointPoller);
   699→    httpServer.close();
   700→    process.exit(0);
   701→  };
   702→  process.on("SIGINT", shutdown);
   703→  process.on("SIGTERM", shutdown);
   704→
   705→  await new Promise<void>((resolve) => {
   706→    httpServer.listen(port, () => {
   707→      process.stderr.write(`claude-hook-handler serve: listening on http://localhost:${port}\n`);
   708→      resolve();
   709→    });
   710→  });
   711→}
