   171→function CheckpointRow({ checkpoint, onPress }: { checkpoint: SessionCheckpoint; onPress: () => void }) {
   172→  const [expanded, setExpanded] = useState(false);
   173→  const outTokens = checkpoint.tokenUsage?.outputTokens ?? 0;
   174→  const fileCount = checkpoint.filesTouched.length;
