   180→      <UnstyledButton
   181→        onClick={() => setExpanded((v) => !v)}
   182→        style={{ width: "100%", display: "flex", alignItems: "center", gap: 10, padding: "8px 12px", backgroundColor: "light-dark(var(--mantine-color-teal-0), var(--mantine-color-dark-6))" }}
   183→      >
   184→        <Box style={{ flex: 1 }}>
   185→          <Group gap={8} mb={2}>
   186→            <Text size="xs" fw={700} c="teal" tt="uppercase">Checkpoint</Text>
