   192→          )}
   193→        </Box>
   194→        <Box style={{ textAlign: "right", flexShrink: 0 }}>
   195→          {fileCount > 0 && <Text size="xs" c="dimmed" ff="monospace">{fileCount} file{fileCount !== 1 ? "s" : ""}</Text>}
   196→          {outTokens > 0 && <Text size="xs" c="dimmed" ff="monospace">{outTokens.toLocaleString()} tok</Text>}
   197→        </Box>
   198→      </UnstyledButton>
   199→
   200→      <Collapse in={expanded}>
   201→        <Box style={{ backgroundColor: "light-dark(var(--mantine-color-teal-0), var(--mantine-color-dark-7))", borderTop: "1px solid var(--mantine-color-teal-2)", padding: "12px 16px", display: "flex", flexDirection: "column", gap: 8 }}>
   202→          {sum?.outcome && (
   203→            <Box>
   204→              <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={2}>✓ Outcome</Text>
   205→              <Text size="xs">{sum.outcome}</Text>
