   214→          {sum?.codeLearnings?.length ? (
   215→            <Box>
   216→              <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={2}>{"</>"} Code learnings</Text>
   217→              {sum.codeLearnings.map((it, i) => (
   218→                <Box key={i} pl={4} mb={2}>
