   221→                </Box>
   222→              ))}
   223→            </Box>
   224→          ) : null}
   225→          {sum?.workflowLearnings?.length ? (
   226→            <Box>
   227→              <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={2}>↺ Workflow learnings</Text>
   228→              {sum.workflowLearnings.map((it, i) => <Text key={i} size="xs">· {it}</Text>)}
   229→            </Box>
   230→          ) : null}
   231→          {sum?.friction?.length ? (
