   262→export function SessionDetail() {
   263→  const navigate = useNavigate();
   264→  const { sessionId } = useParams<{ sessionId: string }>();
   265→  const [session, setSession] = useState<Session | null>(null);
   266→  const [latestCheckpoint, setLatestCheckpoint] = useState<SessionCheckpoint | null>(null);
   267→  const [items, setItems] = useState<RenderItem[]>([]);
   268→  const [userInfo, setUserInfo] = useState<UserInfo | undefined>(undefined);
   269→  const [openItems, setOpenItems] = useState<OpenItem[]>([]);
   270→  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
   271→  const [spawning, setSpawning] = useState(false);
   272→  const [loading, setLoading] = useState(true);
   273→  const [error, setError] = useState<string | null>(null);
   274→
   275→  const id = sessionId!;
   276→  const { setCrumbs } = useBreadcrumb();
   277→
   278→  useEffect(() => {
   279→    Promise.all([fetchSession(id), fetchSessionEvents(id), fetchSessionCheckpoints(id)])
   280→      .then(([s, evs, checkpoints]) => {
   281→        setSession(s);
   282→        const user = s.gitUserName ?? s.gitUserEmail ?? null;
   283→        const repo = s.repoName ?? null;
   284→        const shortId = s.sessionId.slice(0, 8) + "…";
   285→        if (user) {
   286→          setUserInfo({
   287→            name: s.gitUserName ?? user,
   288→            avatarUrl: s.gitUserName ? `https://github.com/${s.gitUserName}.png?size=40` : undefined,
   289→          });
   290→        }
   291→        setCrumbs([
   292→          ...(user ? [{ label: user, path: "/" }] : []),
   293→          ...(repo ? [{ label: repo, path: "/" }] : []),
   294→          { label: shortId },
   295→        ]);
   296→        const grouped = groupEvents(evs);
   297→        const merged: DisplayItem[] = [];
   298→        let cpIdx = 0;
   299→        const sortedCps = [...checkpoints].sort((a, b) => (a.createdAt ?? "") < (b.createdAt ?? "") ? -1 : 1);
   300→        const latest = sortedCps[sortedCps.length - 1] ?? null;
   301→        setLatestCheckpoint(latest);
   302→        setOpenItems(latest?.summary?.openItems ?? []);
   303→
   304→        for (const item of grouped) {
   305→          const itemTime = item.kind === "event" ? item.event.timestamp : item.kind === "toolGroup" ? item.tools[0]?.pre.timestamp ?? "" : "";
   306→          while (cpIdx < sortedCps.length && (sortedCps[cpIdx].createdAt ?? "") <= itemTime) {
   307→            merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
   308→          }
   309→          merged.push(item);
   310→        }
   311→        while (cpIdx < sortedCps.length) merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
   312→
   313→        setItems(groupClaudeTurns(merged));
   314→        setError(null);
   315→      })
   316→      .catch((err: unknown) => setError(String(err)))
   317→      .finally(() => setLoading(false));
   318→  }, [id]);
   319→
   320→  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="indigo" /></Center>;
   321→  if (error) return <Center style={{ flex: 1 }}><Text c="red">{error}</Text></Center>;
   322→
   323→  return (
