   328→          onClick={() => navigate(`/sessions/${session.parentSessionId}`, { state: { title: session.parentSessionId!.slice(0, 8) + "…" } })}
   329→          style={{ width: "100%", display: "flex", alignItems: "center", gap: 6, backgroundColor: "light-dark(var(--mantine-color-blue-0), var(--mantine-color-dark-6))", borderBottom: "1px solid var(--mantine-color-blue-2)", padding: "8px 14px" }}
   330→        >
   331→          <Text size="xs" c="blue">↑ Continuation of</Text>
   332→          <Text size="xs" c="blue" ff="monospace" fw={600} td="underline">{session.parentSessionId.slice(0, 8)}…</Text>
   333→        </UnstyledButton>
   334→      )}
   335→      {session?.childSessionIds?.map((childId) => (
   336→        <UnstyledButton
   337→          key={childId}
   338→          onClick={() => navigate(`/sessions/${childId}`, { state: { title: childId.slice(0, 8) + "…" } })}
   339→          style={{ width: "100%", display: "flex", alignItems: "center", gap: 6, backgroundColor: "light-dark(var(--mantine-color-green-0), var(--mantine-color-dark-6))", borderBottom: "1px solid var(--mantine-color-green-2)", padding: "8px 14px" }}
   340→        >
   341→          <Text size="xs" c="green">↓ Continued as</Text>
   342→          <Text size="xs" c="green" ff="monospace" fw={600} td="underline">{childId.slice(0, 8)}…</Text>
   343→        </UnstyledButton>
   344→      ))}
   345→
   346→      {latestCheckpoint?.summary && (
   347→        <Box style={{
   348→          borderBottom: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))",
   349→          padding: "16px 20px",
   350→          backgroundColor: "light-dark(var(--mantine-color-gray-0), var(--mantine-color-dark-7))",
   351→        }}>
   352→          <Text size="sm" fw={600} lh={1.5} mb={latestCheckpoint.summary.openItems?.length ? 12 : 0}>
   353→            {latestCheckpoint.summary.intent}
   354→          </Text>
   355→          {openItems.length > 0 && (
   356→            <Box>
   357→              <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={8} style={{ letterSpacing: 0.5 }}>
   358→                Open items
   359→              </Text>
   360→              {openItems.map((item, i) => {
   361→                const selectable = item.status === "open";
   362→                const statusColor = item.status === "complete" ? "teal" : item.status === "in_progress" ? "orange" : item.status === "na" ? "gray" : "blue";
   363→                const statusLabel = item.status === "in_progress" ? "in progress" : item.status === "na" ? "n/a" : item.status;
   364→                return (
   365→                  <Group key={item.id} gap={10} align="flex-start" mb={6} wrap="nowrap">
   366→                    {selectable ? (
   367→                      <Checkbox
   368→                        size="xs"
