   395→                      <Menu.Dropdown>
   396→                        {(["open", "in_progress", "complete", "na"] as const).map((s) => (
   397→                          <Menu.Item
   398→                            key={s}
   399→                            fw={item.status === s ? 700 : undefined}
   400→                            onClick={async () => {
   401→                              await updateOpenItemStatus(item.id, s).catch(() => undefined);
   402→                              setOpenItems((prev) => prev.map((it) => it.id === item.id ? { ...it, status: s } : it));
   403→                              if (s !== "open") setSelectedItems((prev) => { const n = new Set(prev); n.delete(i); return n; });
   404→                            }}
   405→                          >
   406→                            {s === "in_progress" ? "in progress" : s === "na" ? "n/a" : s}
   407→                          </Menu.Item>
